export function getCidadesByUF(uf: string): CidadeUSA[] {
  return cidadesUSA.filter((c) => c.uf === uf.toUpperCase());
}

export function getTopCidadesByUF(uf: string, n = 5): CidadeUSA[] {
  return getCidadesByUF(uf)
    .sort((a, b) => b.score_oportunidade - a.score_oportunidade)
    .slice(0, n);
}
